// Procedural macros for Ziee Chat
//
// This crate provides various procedural macros used throughout the application.

use proc_macro::TokenStream;
use quote::quote;
use syn::{parse_macro_input, ItemEnum, ItemStruct};

// Embed the generated extensions code at compile time
// This is generated by build.rs and included here
const EXTENSIONS_CODE: &str = include_str!(concat!(env!("OUT_DIR"), "/chat_extensions.rs"));

/// Macro to include the auto-generated extension registration code
/// This expands to the entire generated module content
#[proc_macro]
pub fn include_chat_extensions(_item: TokenStream) -> TokenStream {
    EXTENSIONS_CODE.parse().unwrap()
}

/// Attribute macro to compose all discovered chat extension request fields
///
/// This macro automatically discovers all extension.rs files in modules/chat/**/
/// parses their SendMessageRequestFields, and adds the fields directly to the target struct.
///
/// Usage:
/// ```
/// #[compose_chat_extensions]
/// pub struct SendMessageRequest {
///     pub content: String,
///     pub parent_id: Option<Uuid>,
/// }
/// ```
///
/// Extensions are discovered by the build script and fields are added directly.
#[proc_macro_attribute]
pub fn compose_chat_extensions(_attr: TokenStream, item: TokenStream) -> TokenStream {
    compose_fields(item, "REQUEST_FIELDS")
}

/// Attribute macro to compose all discovered chat extension response fields
///
/// This macro automatically discovers all extension.rs files in modules/chat/**/
/// parses their ChatStreamChunkFields, and adds the fields directly to the target struct.
///
/// Usage:
