/// Helper function to compose enum variants from generated code
fn compose_enum_variants(item: TokenStream, const_name: &str) -> TokenStream {
    let mut item_enum = parse_macro_input!(item as ItemEnum);

    // Parse extension enum variant definitions from the embedded code
    let extension_variants: Vec<syn::Variant> = EXTENSIONS_CODE
        .lines()
        .skip_while(|line| !line.contains(const_name))  // Skip until we find the right const
        .skip(1)  // Skip the const declaration line
        .take_while(|line| !line.contains("];"))  // Take until end of array
        .filter_map(|line| {
            let trimmed = line.trim();
            // Look for lines that end with "," (variant definitions)
            if trimmed.ends_with(',') && !trimmed.starts_with("//") {
                // Remove trailing comma and wrap in enum for parsing
                let variant_str = trimmed.trim_end_matches(',');
                let wrapped = format!("enum Dummy {{ {} }}", variant_str);

                // Parse as enum and extract the variant
                if let Ok(parsed_enum) = syn::parse_str::<syn::ItemEnum>(&wrapped) {
                    return parsed_enum.variants.into_iter().next();
                }
                None
            } else {
                None
            }
        })
        .collect();

    // Add extension variants to the enum
    for variant in extension_variants {
        item_enum.variants.push(variant);
    }

    quote! {
        #item_enum
    }
    .into()
}

/// Helper function to compose fields from generated code
fn compose_fields(item: TokenStream, const_name: &str) -> TokenStream {
    let mut item_struct = parse_macro_input!(item as ItemStruct);

    // Parse extension field definitions from the embedded code
    let extension_fields: Vec<syn::Field> = EXTENSIONS_CODE
        .lines()
        .skip_while(|line| !line.contains(const_name))  // Skip until we find the right const
        .skip(1)  // Skip the const declaration line
        .take_while(|line| !line.contains("];"))  // Take until end of array
        .filter_map(|line| {
            let trimmed = line.trim();
            // Look for lines that end with "," (field definitions)
            if trimmed.ends_with(',') && !trimmed.starts_with("//") {
                // Remove trailing comma and wrap in struct for parsing
                let field_str = trimmed.trim_end_matches(',');
                let wrapped = format!("struct Dummy {{ {} }}", field_str);

                // Parse as struct and extract the field
                if let Ok(parsed_struct) = syn::parse_str::<syn::ItemStruct>(&wrapped) {
                    if let syn::Fields::Named(fields_named) = parsed_struct.fields {
                        return fields_named.named.into_iter().next();
                    }
                }
                None
            } else {
                None
            }
        })
        .collect();

    // Add extension fields directly to the struct
    if let syn::Fields::Named(ref mut fields) = item_struct.fields {
        for field in extension_fields {
            fields.named.push(field);
        }
    }

    quote! {
        #item_struct
    }
    .into()
}

